+            if let Some(first) = self.saved_endpoints.first() {
+                self.base_url = first.url.clone();
+                if !self.streaming {
+                    self.fetch_models();
+                }
+            }
+        } else {
+            // Also need to re-fetch models if the API key for the current endpoint changed
+            if !self.streaming {
+                self.fetch_models();
+            }
+        }
